rules = {
    # AWS Managed Rule Groups
    common-rule-set = {
      priority        = 1
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesCommonRuleSet"
          vendor_name = "AWS"
        }
      }
    }

    sqli-rule-set = {
      priority        = 2
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesSQLiRuleSet"
          vendor_name = "AWS"
        }
      }
    }

    known-bad-inputs = {
      priority        = 3
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesKnownBadInputsRuleSet"
          vendor_name = "AWS"
        }
      }
    }

    # Managed rule group with scope_down_statement using regex_match_statement
    # Excludes specific URI paths from the admin protection rule set
    admin-protection-scoped = {
      priority        = 4
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesAdminProtectionRuleSet"
          vendor_name = "AWS"

          scope_down_statement = {
            regex_match_statement = {
              regex_string = "^/admin/.*"
              field_to_match = {
                uri_path = {}
              }
              text_transformations = [
                {
                  priority = 0
                  type     = "LOWERCASE"
                }
              ]
            }
          }
        }
      }
    }

    # Managed rule group with scope_down_statement using not_statement
    # Applies the common rule set only to requests NOT matching a specific path
    common-rules-scoped = {
      priority        = 5
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesCommonRuleSet"
          vendor_name = "AWS"

          scope_down_statement = {
            not_statement = {
              statement = {
                byte_match_statement = {
                  positional_constraint = "STARTS_WITH"
                  search_string         = "/api/health"
                  field_to_match = {
                    uri_path = {}
                  }
                  text_transformations = [
                    {
                      priority = 0
                      type     = "LOWERCASE"
                    }
                  ]
                }
              }
            }
          }
        }
      }
    }

    # Managed rule group with scope_down_statement using and_statement
    # Applies the common rule set only to requests matching a specific path AND a http method POST
    common-rules-scoped-with-and = {
      priority        = 6
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesCommonRuleSet"
          vendor_name = "AWS"

          scope_down_statement = {
            and_statement = {
              statements = [
                {
                  byte_match_statement = {
                    positional_constraint = "STARTS_WITH"
                    search_string         = "/login"
                    field_to_match = {
                      uri_path = {}
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "LOWERCASE"
                      }
                    ]
                  }
                },
                {
                  byte_match_statement = {
                    positional_constraint = "EXACTLY"
                    search_string         = "POST"
                    field_to_match = {
                      method = {}
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "NONE"
                      }
                    ]
                  }
                }
              ]
            }
          }
        }
      }
    }

    # Managed rule group with scope_down_statement using or_statement
    # Applies the common rule set only to requests matching a specific path OR a specific body
    common-rules-scoped-with-or = {
      priority        = 7
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesCommonRuleSet"
          vendor_name = "AWS"

          scope_down_statement = {
            or_statement = {
              statements = [
                {
                  byte_match_statement = {
                    positional_constraint = "STARTS_WITH"
                    search_string         = "/login"
                    field_to_match = {
                      uri_path = {}
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "LOWERCASE"
                      }
                    ]
                  }
                },
                {
                  byte_match_statement = {
                    positional_constraint = "EXACTLY"
                    search_string         = "action: login"
                    field_to_match = {
                      body = {
                        oversize_handling = "CONTINUE"
                      }
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "NONE"
                      }
                    ]
                  }
                }
              ]
            }
          }
        }
      }
    }

    # IP set reference rule
    block-bad-ips = {
      priority = 10
      action   = "block"

      statement = {
        ip_set_reference_statement = {
          arn = module.ip_set.arn
        }
      }
    }

    # Geo match rule - block specific countries
    geo-block = {
      priority = 20
      action = {
        block = {
          custom_response = {
            response_code            = 403
            custom_response_body_key = "blocked_response"
          }
        }
      }

      statement = {
        geo_match_statement = {
          country_codes = ["RU", "CN"]
        }
      }
    }

    # Rate-based rule
    rate-limit = {
      priority = 30
      action   = "block"

      statement = {
        rate_based_statement = {
          limit                 = 1000
          aggregate_key_type    = "IP"
          evaluation_window_sec = 300
        }
      }
    }

    # Rate-based rule with compound scope_down_statement.
    # Rate-limits only login POSTs to /login (URI AND method match).
    rate-limit-login-scoped = {
      priority = 31
      action   = "block"

      statement = {
        rate_based_statement = {
          limit                 = 100
          aggregate_key_type    = "IP"
          evaluation_window_sec = 300

          scope_down_statement = {
            and_statement = {
              statements = [
                {
                  byte_match_statement = {
                    positional_constraint = "STARTS_WITH"
                    search_string         = "/login"
                    field_to_match = {
                      uri_path = {}
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "LOWERCASE"
                      }
                    ]
                  }
                },
                {
                  byte_match_statement = {
                    positional_constraint = "EXACTLY"
                    search_string         = "POST"
                    field_to_match = {
                      method = {}
                    }
                    text_transformations = [
                      {
                        priority = 0
                        type     = "NONE"
                      }
                    ]
                  }
                }
              ]
            }
          }
        }
      }
    }

    # Byte match rule - block requests without specific header
    require-api-key = {
      priority = 40
      action   = "block"

      statement = {
        byte_match_statement = {
          positional_constraint = "EXACTLY"
          search_string         = "valid-api-key"
          field_to_match = {
            single_header = {
              name = "x-api-key"
            }
          }
          text_transformations = [
            {
              priority = 0
              type     = "NONE"
            }
          ]
        }
      }
    }

    # Size constraint rule
    limit-body-size = {
      priority = 50
      action   = "block"

      statement = {
        size_constraint_statement = {
          comparison_operator = "GT"
          size                = 8192
          field_to_match = {
            body = {
              oversize_handling = "MATCH"
            }
          }
          text_transformations = [
            {
              priority = 0
              type     = "NONE"
            }
          ]
        }
      }
    }

    # Nested compound: AND containing an OR among its child statements.
    # Demonstrates the L2 OR-inside-AND path together with the byte_match
    # `body` field-target — both shipped in this PR.
    nested-compound-demo = {
      priority = 60
      action   = "block"

      statement = {
        and_statement = {
          statements = [
            {
              geo_match_statement = {
                country_codes = ["US"]
              }
            },
            {
              or_statement = {
                statements = [
                  {
                    byte_match_statement = {
                      positional_constraint = "CONTAINS"
                      search_string         = "DROP TABLE"
                      field_to_match = {
                        body = {
                          oversize_handling = "MATCH"
                        }
                      }
                      text_transformations = [
                        {
                          priority = 0
                          type     = "LOWERCASE"
                        }
                      ]
                    }
                  },
                  {
                    ip_set_reference_statement = {
                      arn = module.ip_set.arn
                    }
                  }
                ]
              }
            }
          ]
        }
      }
    }

    # ASN match — block requests originating from a specific Autonomous System
    block-asn = {
      priority = 70
      action   = "block"

      statement = {
        asn_match_statement = {
          asn_list = [12389, 65535]
        }
      }
    }

    # Byte match using uri_fragment + ja4_fingerprint
    block-by-uri-fragment-and-ja4 = {
      priority = 71
      action   = "block"

      statement = {
        and_statement = {
          statements = [
            {
              byte_match_statement = {
                positional_constraint = "CONTAINS"
                search_string         = "debug"
                field_to_match = {
                  uri_fragment = {
                    fallback_behavior = "MATCH"
                  }
                }
                text_transformations = [
                  {
                    priority = 0
                    type     = "LOWERCASE"
                  }
                ]
              }
            },
            {
              byte_match_statement = {
                positional_constraint = "STARTS_WITH"
                search_string         = "abc123"
                field_to_match = {
                  ja4_fingerprint = {
                    fallback_behavior = "NO_MATCH"
                  }
                }
                text_transformations = [
                  {
                    priority = 0
                    type     = "NONE"
                  }
                ]
              }
            }
          ]
        }
      }
    }

    # Rate-based with JA3 fingerprint as a custom aggregate key
    rate-by-ja3 = {
      priority = 72
      action   = "block"

      statement = {
        rate_based_statement = {
          limit                 = 200
          aggregate_key_type    = "CUSTOM_KEYS"
          evaluation_window_sec = 300

          custom_keys = [
            {
              ja3_fingerprint = {
                fallback_behavior = "NO_MATCH"
              }
            },
            {
              header = {
                name = "x-client-id"
                text_transformations = [
                  {
                    priority = 0
                    type     = "NONE"
                  }
                ]
              }
            }
          ]
        }
      }
    }

    # Anti-DDoS managed rule group
    aws-anti-ddos = {
      priority        = 73
      override_action = "none"

      statement = {
        managed_rule_group_statement = {
          name        = "AWSManagedRulesAntiDDoSRuleSet"
          vendor_name = "AWS"

          managed_rule_group_configs = [
            {
              aws_managed_rules_anti_ddos_rule_set = {
                sensitivity_to_block = "MEDIUM"
                client_side_action_config = {
                  challenge = {
                    usage_of_action = "ENABLED"
                    sensitivity     = "HIGH"
                    exempt_uri_regular_expression = [
                      {
                        regex_string = "^/health$"
                      }
                    ]
                  }
                }
              }
            }
          ]
        }
      }
    }
  }

rules = {
    block-high-risk-geos = {
      priority = 0
      action   = "block"
      statement = {
        geo_match_statement = {
          country_codes = ["RU", "BY", "KP"]
        }
      }
      visibility_config = {
        cloudwatch_metrics_enabled = true
        metric_name                = "block-high-risk-geos"
        sampled_requests_enabled   = true
      }
    }

    count-admin-uri = {
      priority = 1
      action   = "count"
      statement = {
        byte_match_statement = {
          search_string         = "/admin"
          positional_constraint = "STARTS_WITH"
          field_to_match = {
            uri_path = {}
          }
          text_transformations = [
            {
              priority = 0
              type     = "LOWERCASE"
            },
          ]
        }
      }
      visibility_config = {
        cloudwatch_metrics_enabled = true
        metric_name                = "count-admin-uri"
        sampled_requests_enabled   = true
      }
    }
  }
